// In your terminal, type:
// node --version
// You should see something like: v20.11.0

// hello.js
console.log("Hello from a file!");

// In your terminal:
// node hello.js
// Output: Hello from a file!

let count = 0;
count = 1; // OK
console.log(count); // 1

const PI = 3.14;
const person = { name: "Alice" };
person.name = "Bob"; // OK — object is mutable
// PI = 3; // TypeError

const greeting = "Hello";
let score = 0;
score += 10;
console.log(greeting, score); // Hello 10

const name = "Alice";   // string
const age = 30;          // number
const isHappy = true;    // boolean
let score;               // undefined (no value assigned)
const empty = null;      // null (intentionally empty)

let a;
console.log(a);        // undefined

let b = null;
console.log(b);        // null

console.log(a == b);   // true  (loose equality)
console.log(a === b);  // false (strict equality)

const single = 'Hello';
const double = "World";
const backtick = `Hi there`;

console.log(single, double, backtick);

const name = "Alice";
const age = 25;

// Old way — concatenation
console.log("Name: " + name + ", Age: " + age);

// Modern way — template literal
console.log(`Name: ${name}, Age: ${age}`);
console.log(`Next year you will be ${age + 1}`);

const poem = `Roses are red,
Violets are blue,
JavaScript is fun,
And so are you.`;

console.log(poem);

const integer = 42;
const decimal = 3.14;
const scientific = 2.5e3; // 2500

console.log(integer, decimal, scientific);
console.log(typeof integer);  // "number"
console.log(typeof decimal);  // "number"

const isLoggedIn = true;
const hasPermission = false;

console.log(isLoggedIn);      // true
console.log(typeof hasPermission); // "boolean"

// Falsy values
if (!false) console.log("false is falsy");
if (!0) console.log("0 is falsy");
if (!"") console.log("empty string is falsy");
if (!null) console.log("null is falsy");
if (!undefined) console.log("undefined is falsy");

// Truthy surprises
if ([]) console.log("empty array is truthy!");
if ({}) console.log("empty object is truthy!");

const age = 20;
const label = age >= 18 ? "adult" : "minor";
console.log(label); // "adult"

const score = 85;
console.log(`Grade: ${score >= 90 ? "A" : "B or below"}`);

const temperature = 35;

if (temperature > 30) {
  console.log("It's hot outside!");
}
// Output: It's hot outside!

const score = 75;

if (score >= 90) {
  console.log("A");
} else if (score >= 80) {
  console.log("B");
} else if (score >= 70) {
  console.log("C");
} else {
  console.log("Needs improvement");
}
// Output: C

const day = "Monday";

switch (day) {
  case "Monday":
    console.log("Start of the work week");
    break;
  case "Friday":
    console.log("Almost weekend!");
    break;
  case "Saturday":
  case "Sunday":
    console.log("Weekend!");
    break;
  default:
    console.log("Midweek");
}

// Range check — if/else is natural
const age = 15;
if (age < 13) {
  console.log("child");
} else if (age < 18) {
  console.log("teenager");
} else {
  console.log("adult");
}
// Output: teenager

for (let i = 0; i < 5; i++) {
  console.log(i);
}
// Output: 0, 1, 2, 3, 4

const fruits = ["apple", "banana", "cherry"];

for (let i = 0; i < fruits.length; i++) {
  console.log(`${i}: ${fruits[i]}`);
}
// 0: apple
// 1: banana
// 2: cherry

const colors = ["red", "green", "blue"];

for (const color of colors) {
  console.log(color);
}
// red
// green
// blue

// Works with strings too
for (const char of "Hi!") {
  console.log(char);
}
// H, i, !

let count = 0;

while (count < 5) {
  console.log(count);
  count++;
}
// Output: 0, 1, 2, 3, 4

let num = 10;

do {
  console.log(num);
  num += 10;
} while (num <= 30);
// Output: 10, 20, 30

// break — stop at 3
for (let i = 0; i < 10; i++) {
  if (i === 3) break;
  console.log(i);
}
// Output: 0, 1, 2

// continue — skip even numbers
for (let i = 0; i < 6; i++) {
  if (i % 2 === 0) continue;
  console.log(i);
}
// Output: 1, 3, 5

// BAD — infinite loop (don't run this!)
// let x = 1;
// while (x > 0) { x++; } // x only grows!

// GOOD — condition eventually becomes false
let x = 10;
while (x > 0) {
  console.log(x);
  x -= 3;
}
// Output: 10, 7, 4, 1

function greet(name) {
  console.log(`Hello, ${name}!`);
}

greet("Alice"); // Hello, Alice!
greet("Bob");   // Hello, Bob!

function add(a, b) {
  return a + b;
}

const sum = add(3, 7);
console.log(sum); // 10

function noReturn() {
  console.log("I run but return nothing");
}
console.log(noReturn()); // undefined

// Regular function
const square = function (n) {
  return n * n;
};

// Arrow function (concise)
const squareArrow = (n) => n * n;

console.log(square(4));      // 16
console.log(squareArrow(4)); // 16

// Arrow with multiple statements
const describe = (name) => {
  const upper = name.toUpperCase();
  return `Name: ${upper}`;
};

function greet(name = "stranger") {
  return `Hello, ${name}!`;
}

console.log(greet("Alice")); // Hello, Alice!
console.log(greet());        // Hello, stranger!

const global = "I am everywhere";

function example() {
  const local = "I am only in this function";
  console.log(global); // works
  console.log(local);  // works
}

example();
// console.log(local); // ReferenceError!

const appName = "MyApp"; // global

function printApp() {
  console.log(appName); // accessible
}

printApp(); // MyApp
console.log(appName); // MyApp

function demo() {
  if (true) {
    var a = 1;   // function-scoped
    let b = 2;   // block-scoped
    const c = 3; // block-scoped
  }
  console.log(a); // 1 (var leaks out of the block)
  // console.log(b); // ReferenceError
  // console.log(c); // ReferenceError
}

demo();

const outer = "outer";

function parent() {
  const middle = "middle";

  function child() {
    const inner = "inner";
    console.log(inner);  // "inner"  (own scope)
    console.log(middle); // "middle" (parent scope)
    console.log(outer);  // "outer"  (global scope)
  }

  child();
}

parent();

const fruits = ["apple", "banana", "cherry"];
const mixed = [1, "two", true, null];

console.log(fruits.length); // 3
console.log(mixed.length);  // 4

const colors = ["red", "green", "blue"];

console.log(colors[0]); // "red"
console.log(colors[2]); // "blue"
console.log(colors[5]); // undefined

colors[1] = "yellow";
console.log(colors); // ["red", "yellow", "blue"]

const pets = ["cat", "dog", "fish"];

// for...of
for (const pet of pets) {
  console.log(pet);
}

// forEach
pets.forEach((pet, index) => {
  console.log(`${index}: ${pet}`);
});
// 0: cat
// 1: dog
// 2: fish

const person = {
  name: "Alice",
  age: 30,
  hobbies: ["reading", "coding"]
};

console.log(person);

const car = { brand: "Toyota", year: 2022 };

// Dot notation
console.log(car.brand); // "Toyota"

// Bracket notation
console.log(car["year"]); // 2022

// Dynamic key
const key = "brand";
console.log(car[key]); // "Toyota"

const user = { name: "Bob" };

// Add
user.email = "bob@example.com";

// Update
user.name = "Robert";

// Delete
delete user.email;

console.log(user);            // { name: "Robert" }
console.log("name" in user);   // true
console.log("email" in user);  // false

const scores = { math: 95, english: 88, science: 92 };

// for...in
for (const subject in scores) {
  console.log(`${subject}: ${scores[subject]}`);
}

// Object.entries
for (const [key, value] of Object.entries(scores)) {
  console.log(`${key} → ${value}`);
}

console.log("Hello!");
console.log("x =", 10, "y =", 20);

const user = { name: "Alice", age: 30 };
console.log("User:", user);

console.warn("Deprecated function called");
console.error("Failed to load data!");

// They accept multiple arguments too
const code = 404;
console.error("Status:", code, "— Not Found");

const users = [
  { name: "Alice", age: 30 },
  { name: "Bob", age: 25 },
  { name: "Charlie", age: 35 }
];

console.table(users);
// Displays a neat table with columns: (index), name, age

console.dir(document.body); // tree view in browsers

console.time("loop");
for (let i = 0; i < 100000; i++) {}
console.timeEnd("loop"); // loop: 1.23ms

console.group("User Details");
console.log("Name: Alice");
console.log("Age: 30");
console.groupEnd();

const a = [1, 2];
const b = [...a, 3, 4]; // [1, 2, 3, 4]
const [first, second] = b;

function makeCounter() {
  let count = 0;
  return () => ++count;
}

const counter = makeCounter();
console.log(counter()); // 1
console.log(counter()); // 2

for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// prints 0, 1, 2 — not 3, 3, 3

console.log("1");
setTimeout(() => console.log("4"), 0);
Promise.resolve().then(() => console.log("3"));
console.log("2");
// Output: 1, 2, 3, 4
